As an AI text model, I cannot directly render 3D graphics or display interactive models in this chat interface. However, I can provide you with the **code** to render a 3D house model using popular libraries like **Three.js** (for the web) or **Blender** (for professional 3D modeling).

Below is a complete, single-file HTML/JavaScript solution using **Three.js**. You can save this code as an `.html` file (e.g., `house.html`) and open it in any modern web browser to see the 3D house.

### 3D House Model (Three.js Code)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const glassMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with box
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.5);
        const door = new THREE.Mesh(doorGeo, new THREE.MeshStandardMaterial({ color: 0x5D4037 }));
        door.position.set(0, 2, 4.26); // Slightly in front of wall
        door.castShadow = true;
        houseGroup.add(door);

        // Windows (Simple planes)
        const windowGeo = new THREE.PlaneGeometry(2, 1.5);

        // Front Window
        const win1 = new THREE.Mesh(windowGeo, glassMaterial);
        win1.position.set(0, 4, 4.26);
        houseGroup.add(win1);

        // Side Window
        const win2 = new THREE.Mesh(windowGeo, glassMaterial);
        win2.position.set(4.26, 4, 0);
        win2.rotation.y = Math.PI / 2;
        houseGroup.add(win2);

        // Tree (Simple Cone)
        const treeGeo = new THREE.ConeGeometry(2, 6, 8);
        const treeMat = new THREE.MeshStandardMaterial({ color: 0x228B22 });
        const tree = new THREE.Mesh(treeGeo, treeMat);
        tree.position.set(-6, 3, -6);
        tree.castShadow = true;
        houseGroup.add(tree);

        // Trunk
        const trunkGeo = new THREE.CylinderGeometry(0.5, 0.5, 1);
        const trunkMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const trunk = new THREE.Mesh(trunkGeo, trunkMat);
        trunk.position.set(-6, 0.5, -6);
        houseGroup.add(trunk);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser (Chrome, Firefox, Edge, etc.).

### Alternative: Blender (Professional 3D)
If you are looking to create a high-quality, textured 3D model for animation or game development, I recommend using **Blender** (free and open-source).

1.  Download Blender from blender.org.
2.  Open Blender and go to `File > New` to create a default cube.
3.  Select the cube, press `Tab` to enter Edit Mode, and use `Extrude` (E key) to build walls and a roof.
4.  Add a `Cone` primitive for a roof and a `Cylinder` for a chimney.
5.  Use the `Shade Smooth` option to make the surfaces look rounded rather than blocky.
